// --- Redux/Zustand middleware helpers ---

// Zustand middleware
export const debugLoggerMiddleware = (config) => (set, get, api) =>
  config(
    (...args) => {
      const prevState = get();
      set(...args);
      const nextState = get();

      const changedKeys = Object.keys(nextState).filter(
        key => prevState[key] !== nextState[key]
      );

      if (changedKeys.length > 0) {
        debugLogger.logStateChange('Zustand', 'state_update', {
          changedKeys,
        });
      }
    },
    get,
    api
  );


// --- API Helper with built-in logging ---

export const createTrackedApiClient = (baseUrl, defaultHeaders = {}) => {
  const client = {
    async request(method, path, options = {}) {
      const timer = debugLogger.startTimer(`API ${method} ${path}`);
      const url = `${baseUrl}${path}`;

      try {
        const response = await fetch(url, {
          method,
          headers: {
            'Content-Type': 'application/json',
            ...defaultHeaders,
            ...options.headers,
          },
          body: options.body ? JSON.stringify(options.body) : undefined,
        });

        debugLogger.endTimer(timer);

        if (!response.ok) {
          const errorBody = await response.text().catch(() => 'Unable to read error body');
          debugLogger.error('API_CLIENT', `API Error: ${method} ${path}`, {
            status: response.status,
            // Redact error body in case it contains sensitive data
            errorHint: errorBody.substring(0, 100),
          });
        }

        return response;
      } catch (error) {
        debugLogger.endTimer(timer);
        debugLogger.error('API_CLIENT', `API Request Failed: ${method} ${path}`, {
          error: error.message,
        });
        throw error;
      }
    },

    get: (path, options) => client.request('GET', path, options),
    post: (path, body, options = {}) => client.request('POST', path, { ...options, body }),
    put: (path, body, options = {}) => client.request('PUT', path, { ...options, body }),
    patch: (path, body, options = {}) => client.request('PATCH', path, { ...options, body }),
    delete: (path, options) => client.request('DELETE', path, options),
  };

  return client;
};


